transform_js:
transformedData = rawData.series.map(function(s) {
  return {
    name: s.name,
    type: 'line',
    data: s.values,
    symbol: 'circle',
    symbolSize: 10,
    lineStyle: { width: 2 }
  };
});
transformedData._categories = rawData.categories;

echarts_js:
option = {
  title: { text: 'Quarterly Ranking (Connected Dots)', left: 'center' },
  tooltip: { trigger: 'axis' },
  legend: { bottom: '5%' },
  xAxis: { type: 'category', data: transformedData._categories },
  yAxis: { type: 'value', name: 'Score' },
  series: transformedData.filter(function(s) { return s.type; })
};
